    # Input must be a pair (list_of_ints, k) where k is a positive integer
    if not isinstance(i, (list, tuple)) or len(i) != 2:
        return False
    lst, k = i
    if not isinstance(lst, list):
        return False
    if not all(isinstance(x, int) for x in lst):
        return False
    if not isinstance(k, int) or k <= 0:
        return False
    return True

def post(i, o):
    # Correct output for a valid input
    if not pre(i):
        return False
    lst, k = i
    n = len(lst)
    if k > n:
        return o is None
    # k-th smallest (1‑based) element
    kth = sorted(lst)[k - 1]
    return o == kth

